46	
47	template<typename T>
48	constexpr T RoundDown(T x, std::remove_reference_t<T> n) {
49	    return (x & -n);
50	}
51	
52	template<typename T>
53	constexpr T RoundUp(T x, std::remove_reference_t<T> n) {
54	    return RoundDown(x + n - 1, n);
55	}
