57	class Opencore {
58	public:
59	    static constexpr int FLAG_CORE = 1 << 0;
60	    static constexpr int FLAG_PROCESS_COMM = 1 << 1;
61	    static constexpr int FLAG_PID = 1 << 2;
62	    static constexpr int FLAG_THREAD_COMM = 1 << 3;
63	    static constexpr int FLAG_TID = 1 << 4;
64	    static constexpr int FLAG_TIMESTAMP = 1 << 5;
65	    static constexpr int FLAG_ALL = FLAG_CORE | FLAG_PROCESS_COMM | FLAG_PID
66	                              | FLAG_THREAD_COMM | FLAG_TID | FLAG_TIMESTAMP;
67	
68	    static constexpr int INVALID_TID = 0;
69	
70	    static constexpr int FILTER_NONE = 0x0;
71	    static constexpr int FILTER_SPECIAL_VMA = 1 << 0;
72	    static constexpr int FILTER_FILE_VMA = 1 << 1;
73	    static constexpr int FILTER_SHARED_VMA = 1 << 2;
74	    static constexpr int FILTER_SANITIZER_SHADOW_VMA = 1 << 3;
75	    static constexpr int FILTER_NON_READ_VMA = 1 << 4;
76	    static constexpr int FILTER_SIGNAL_CONTEXT = 1 << 5;
77	    static constexpr int FILTER_MINIDUMP = 1 << 6;
78	    static constexpr int FILTER_JAVAHEAP_VMA = 1 << 7;
79	    static constexpr int FILTER_JIT_CACHE_VMA = 1 << 8;
80	
81	    static constexpr int VMA_NORMAL = 0;
82	    static constexpr int VMA_NULL = 1 << 0;
83	    static constexpr int VMA_INCLUDE = 1 << 1;
84	
85	    /** only opencore-sdk append **/
86	    static constexpr int DEF_TIMEOUT = 120;
87	
88	    Opencore() {
89	        flag = FLAG_CORE
90	             | FLAG_PID
91	             | FLAG_PROCESS_COMM
92	             | FLAG_TIMESTAMP;
93	        pid = INVALID_TID;
94	        tid = INVALID_TID;
95	        filter = FILTER_NONE;
96	        extra_note_filesz = 0;
97	        page_size = sysconf(_SC_PAGE_SIZE);
98	        align_size = ELF_PAGE_SIZE;
99	
100	        /** only opencore-sdk append **/
101	        ucontext_raw = nullptr;
102	        siginfo = nullptr;
103	        cb = nullptr;
104	        timeout = DEF_TIMEOUT;
105	    }
106	
107	    struct VirtualMemoryArea {
108	        uint64_t begin;
109	        uint64_t end;
110	        char     flags[4];
111	        uint32_t offset;
112	        uint32_t major;
113	        uint32_t minor;
114	        uint64_t inode;
115	        std::string file;
116	    };
117	
118	    struct ThreadRecord {
119	        int pid;
120	        bool attached;
121	    };
122	
123	    void setDir(const char* d) { dir = d; }
124	    void setPid(int p) { pid = p; }
125	    void setTid(int t) { tid = t; }
126	    void setFilter(int f) { filter = f; }
127	    std::string& getDir() { return dir; }
128	    int getFlag() { return flag; }
129	    int getPid() { return pid; }
130	    int getTid() { return tid; }
131	    int getFilter() { return filter; }
132	    int getExtraNoteFilesz() { return extra_note_filesz; }
133	    bool Coredump(const char* filename);
134	    virtual void Finish();
135	    virtual bool DoCoredump(const char* filename) { return false; }
136	    virtual int NeedFilterFile(Opencore::VirtualMemoryArea& vma) { return VMA_NORMAL; }
137	    virtual int getMachine() { return EM_NONE; }
138	    int IsFilterSegment(Opencore::VirtualMemoryArea& vma);
139	    void StopTheWorld(int pid);
140	    bool StopTheThread(int tid);
141	    void Continue();
142	    static void ParseMaps(int pid, std::vector<VirtualMemoryArea>& maps);
143	
144	    /** only opencore-sdk append **/
145	    void setFlag(int f) { flag = f; }
146	    void setTimeout(int sec) { timeout = sec; }
147	    void setContext(void *raw) { ucontext_raw = raw; }
148	    void setSignalInfo(void* info) { siginfo = info; }
149	    void setCallback(DumpCallback callback) { cb = callback; }
150	    int getTimeout() { return timeout; }
151	    void* getContext() { return ucontext_raw; }
152	    void* getSignalInfo() { return siginfo; }
153	    DumpCallback getCallback() { return cb; }
154	
155	    static Opencore* GetInstance();
156	    static const char* GetVersion() { return __OPENCORE_VERSION__; }
157	    static void HandleSignal(int signal, siginfo_t* siginfo, void* ucontext_raw);
158	
159	    class DumpOption {
160	    public:
161	        DumpOption()
162	            : filename(nullptr),
163	              pid(INVALID_TID), tid(INVALID_TID),
164	              siginfo(nullptr), context(nullptr) {}
165	        char* filename;
166	        int pid;
167	        int tid;
168	        void* siginfo;
169	        void* context;
170	    };
171	
172	    static void Dump();
173	    static void Dump(const char* filename);
174	    static void Dump(const char* filename, int tid);
175	    static void Dump(siginfo_t* siginfo, void* ucontext_raw);
176	    static void Dump(DumpOption* option);
177	    static bool Enable();
178	    static bool Disable();
179	    static bool IsEnabled();
180	    static void IgnoreHandler();
181	    static void SetDir(const char* dir);
182	    static void SetCallback(DumpCallback cb);
183	    static void SetFlag(int flag);
184	    static void SetTimeout(int sec);
185	    static void SetFilter(int filter);
186	    static void TimeoutHandle(int);
187	    static const char* GetDir();
188	    static int GetFlag();
189	    static int GetTimeout();
190	    static int GetFilter();
191	protected:
192	    int extra_note_filesz;
193	    std::vector<ThreadRecord> threads;
194	    std::vector<VirtualMemoryArea> maps;
195	    std::vector<uint8_t> zero;
196	    uint32_t align_size;
197	    uint32_t page_size;
198	
199	    /** only opencore-sdk append **/
200	    void* ucontext_raw;
201	    void* siginfo;
202	private:
203	    std::string dir;
204	    int flag;
205	    int pid;
206	    int tid;
207	    int filter;
208	
209	    /** only opencore-sdk append **/
210	    DumpCallback cb;
211	    int timeout;
212	};
213	
214	#endif // OPENCORE_OPENCORE_H_
